code = """import json
import os

# Read the file path from storage
file_path = locals()['var_functions.query_db:28']

# Load all articles from the file
with open(file_path, 'r') as f:
    articles = json.load(f)

# Define keywords for sports articles
sports_keywords = [
    "sport", "sports", "football", "soccer", "cricket", "basketball", "tennis",
    "volleyball", "baseball", "hockey", "rugby", "athlete", "player", "team",
    "coach", "league", "game", "match", "race", "olympic", "tournament",
    "championship", "nba", "nfl", "mlb", "nhl", "world cup", "champion", "medal"
]

# Function to check if article is sports
def is_sports_article(article):
    text = (article.get("title", "") + " " + article.get("description", "")).lower()
    return any(keyword in text for keyword in sports_keywords)

# Filter sports articles
sports_articles = [a for a in articles if is_sports_article(a)]

# Find the sports article with the longest description
max_description_length = -1
article_with_longest_description = None

for article in sports_articles:
    description = article.get("description", "")
    description_length = len(description) if isinstance(description, str) else 0
    
    if description_length > max_description_length:
        max_description_length = description_length
        article_with_longest_description = article

# Get the title of the article with the longest description
title = article_with_longest_description.get("title") if article_with_longest_description else None

print("__RESULT__:")
print(json.dumps(title))"""

